-- ====================================\n-- 创建组织个性化设置表\n-- ====================================\n\n-- 检查组织设置表是否存在\nDO $$\nBEGIN\n    IF NOT EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'organization_settings') THEN\n        CREATE TABLE organization_settings (\n            setting_id SERIAL PRIMARY KEY,\n            organization_id VARCHAR(50) REFERENCES organizations(unit_id) ON DELETE CASCADE,\n            setting_key VARCHAR(50) NOT NULL,\n            setting_value JSONB NOT NULL,\n            created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n            updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n        );
        \n        -- 创建唯一索引，确保每个组织的每个设置键都是唯一的\n        CREATE UNIQUE INDEX idx_organization_setting_unique ON organization_settings(organization_id, setting_key);\n        \n        -- 创建索引以提高查询性能\n        CREATE INDEX idx_organization_id ON organization_settings(organization_id);\n        CREATE INDEX idx_setting_key ON organization_settings(setting_key);\n        \n        RAISE NOTICE '创建表 organization_settings 成功';\n    ELSE\n        RAISE NOTICE '表 organization_settings 已存在';\n    END IF;\nEND $$;\n\n-- 插入默认设置示例数据\nINSERT INTO organization_settings (organization_id, setting_key, setting_value)\nVALUES \n    ('root', 'brand', '{"company_name": "CarpTMS", "subtitle": "智慧运输管理系统", "login_url": "/login", "logo": "", "favicon": ""}'),\n    ('root', 'theme', '{"primary_color": "#409eff", "secondary_color": "#67C23A", "font_family": "Arial, sans-serif", "layout": "default"}')\nON CONFLICT (organization_id, setting_key) DO NOTHING;\n\nSELECT '组织设置表创建完成！' AS info;

